// ItemStackTransactionServiceServer is the server API for ItemStackTransactionService service.
// All implementations must embed UnimplementedItemStackTransactionServiceServer
// for forward compatibility.
//
// ItemStackTransactionService 是单个物品操作事务，
// 它希望使用者尽可能多的将物品堆栈请求内联在一个数据包中，
// 这样可以有效的节省操作的时间消耗。
type ItemStackTransactionServiceServer interface {
	// OpenTransaction 基于 api 创建并返回一个新的 ItemStackTransaction。
	OpenTransaction(context.Context, *OpenTransactionRequest) (*OpenTransactionResponse, error)
	// MoveItem 将 source 处的物品移动到 destination 处，
	// 且只移动 count 个物品。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一
	// 起被内联到单个物品堆栈操作请求中
	MoveItem(context.Context, *MoveItemRequest) (*TransactionActionResponse, error)
	// MoveBetweenInventory 将背包中 source 处的物品移动到 destination 处，
	// 且只移动 count 个物品。
	//
	// 此操作需要保证背包已被打开，或者已打开的容器中可以在背包中移动物品。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起被内联到单个
	// 物品堆栈操作请求中
	MoveBetweenInventory(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// MoveBetweenContainer 将已打开容器中 source 处的物品
	// 移动到已打开容器的 destination 处，且只移动 count 个物品。
	//
	// 此操作需要保证目前已经打开了一个容器，否则效果将会与
	// MoveBetweenInventory 等同。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起被内联
	// 到单个物品堆栈操作请求中
	MoveBetweenContainer(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// MoveToContainer 将背包中 source 处的物品移动到已打开容器的
	// destination 处，且只移动 count 个物品。
	//
	// 此操作需要保证目前已经打开了一个容器，否则效果将会与
	// MoveBetweenInventory 等同。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起被内联
	// 到单个物品堆栈操作请求中
	MoveToContainer(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// MoveToInventory 将已打开容器中 source 处的物品移动到
	// 背包的 destination 处，且只移动 count 个物品。
	//
	// 此操作需要保证目前已经打开了一个容器，否则效果将会与
	// MoveBetweenInventory 等同。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起
	// 被内联到单个物品堆栈操作请求中
	MoveToInventory(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// MoveToCraftingTable 将背包中 source 处的物品移动
	// 到合成栏的 destination 处，且只移动 count 个物品。
	//
	// 此操作需要保证背包已被打开，或打开了工作台，
	// 否则整个事务将会失败。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一
	// 起被内联到单个物品堆栈操作请求中
	MoveToCraftingTable(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// MoveFromCraftingTable 将已放入合成栏 source 处的物品
	// 移动到背包的 destination 处，且只移动 count 个物品。
	//
	// 此操作需要保证背包已被打开，或打开了工作台，否则整个事务
	// 将会失败。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起被
	// 内联到单个物品堆栈操作请求中
	MoveFromCraftingTable(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// SwapItem 交换 source 处和 destination 处的物品。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作
	// 一起被内联到单个物品堆栈操作请求中
	SwapItem(context.Context, *MoveItemRequest) (*TransactionActionResponse, error)
	// SwapBetweenInventory 交换背包中 source
	// 处和背包中 destination 处的物品。
	//
	// 此操作需要保证背包已被打开，或者已打开
	// 的容器中可以在背包中移动物品。
	//
	// 该操作是支持内联的，它会与所有相邻的支
	// 持内联的操作一起被内联到单个物品堆栈操
	// 作请求中
	SwapBetweenInventory(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// SwapInventoryBetweenContainer 交换背包中 source
	// 处和已打开容器 destination 处的物品。
	//
	// 此操作需要保证目前已经打开了一个容器，否则效果将会与
	// SwapInventoryItem 等同。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起
	// 被内联到单个物品堆栈操作请求中
	SwapInventoryBetweenContainer(context.Context, *MoveBySlotRequest) (*TransactionActionResponse, error)
	// DropItem 将 slot 处的物品丢出，且只丢出 count 个。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一
	// 起被内联到单个物品堆栈操作请求中
	DropItem(context.Context, *DropItemRequest) (*TransactionActionResponse, error)
	// DropInventoryItem 将背包中 slot 处的
	// 物品丢出，且只丢出 count 个。
	//
	// 此操作需要保证背包已被打开，
	// 或者已打开的容器中可以在背包中移动物品。
	//
	// 该操作是支持内联的，它会与所有相邻的支
	// 持内联的操作一起被内联到单个物品堆栈操
	// 作请求中
	DropInventoryItem(context.Context, *DropSlotRequest) (*TransactionActionResponse, error)
	// DropContainerItem 将已打开容器 slot 处的物品丢出，且只丢出 count 个。
	//
	// 此操作需要保证目前已经打开了一个容器，否则效果将会与
	// DropInventoryItem 等同。
	//
	// 该操作是支持内联的，它会与所有相邻的支持内联的操作一起被内联
	// 到单个物品堆栈操作请求中
	DropContainerItem(context.Context, *DropSlotRequest) (*TransactionActionResponse, error)
	// GetCreativeItem 从创造物品栏获取 创造物品网络 ID 为
	// creativeItemNetworkID 的物品到 slot 处，
	// 且只移动 count 个物品。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个的物品堆栈操
	// 作请求的数据包中
	GetCreativeItem(context.Context, *CreativeItemRequest) (*TransactionActionResponse, error)
	// GetCreativeItemToInventory 从创造物品栏获取创造物品网络
	// ID 为 creativeItemNetworkID 的物品到背包中的 slot 处，
	// 且只移动 count 个物品。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个的物品堆栈操作请
	// 求的数据包中
	GetCreativeItemToInventory(context.Context, *CreativeItemRequest) (*TransactionActionResponse, error)
	// RenameItem 将 slot 处的物品全部重命名为 newName
	//
	// 重命名操作是通过铁砧完成的，这意味着您需要确保铁砧已被打开，
	// 且铁砧内没有放置任何物品。
	//
	// 如果操作成功，则物品将回到原位。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个的物品堆栈操作请
	// 求的数据包中
	RenameItem(context.Context, *RenameItemRequest) (*TransactionActionResponse, error)
	// RenameInventoryItem 将背包中 slot 处的物品全部重命名为 newName。
	//
	// 重命名操作是通过铁砧完成的，这意味着您需要确保铁砧已被打开，
	// 且铁砧内没有放置任何物品。如果操作成功，则物品将回到原位。
	//
	// 与 RenameItem 的不同之处在于，它只能操作背包中的物品，
	// 因此您需要确保背包已被打开。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个的物品堆栈操作请求的数据包中
	RenameInventoryItem(context.Context, *RenameSlotRequest) (*TransactionActionResponse, error)
	// Looming 将 patternSlot 处的旗帜放入织布机中，
	// 并通过使用 dyeSlot 处的染料合成新旗帜。
	//
	// patternName 是织布时使用的图案，patternSlot
	// 则指示该图案物品的位置。如果无需使用图案，
	// 请将 patternName 和 patternSlot 都置为默认的
	// 零值。
	//
	// resultItem 指示期望得到的旗帜的部分数据。
	// 如果操作成功，则新旗帜将回到原位。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个的物品
	// 堆栈操作请求的数据包中
	Looming(context.Context, *LoomingRequest) (*TransactionActionResponse, error)
	// LoomingFromInventory 将背包中 patternSlot 处的旗帜放入织布机中，
	// 并通过使用背包中 dyeSlot 处的染料合成新旗帜。
	//
	// patternName 是织布时使用的图案，patternSlot 则指示该图案物品
	// 在背包中的位置。如果使用的旗帜图案无需实际的旗帜图案物品用于合成，
	// 请将 patternSlot 置为默认的零值。
	//
	// resultItem 指示期望得到的旗帜的部分数据。
	// 如果操作成功，则新旗帜将回到原位。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个的物品堆栈操作请求的数据包中
	LoomingFromInventory(context.Context, *LoomingRequest) (*TransactionActionResponse, error)
	// Crafting 用于合成一个物品。
	//
	// 它消耗已放入合成栏的全部物品，
	// 然后制作相应的物品到背包。
	//
	// recipeNetworkID 是合成配方的网络 ID；
	// resultSlotID 是合成后物品应当放置的位置；
	// resultCount 是合成后所得物品的数量；
	// resultItem 是合成后物品的最终数据
	Crafting(context.Context, *CraftingRequest) (*TransactionActionResponse, error)
	// Trimming 将下面列出的物品放置在锻造台中，
	// 并进行对于的锻造台的纹饰操作。
	//
	// - trimItemPath 处的 1 个装备
	// - materialPath 处的 1 个材料
	// - templatePath 处的 1 个模板
	//
	// resultItem 指示期望得到的锻造结果数据。
	// 如果操作成功，则被锻造物品将回到原位。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个
	// 的物品堆栈操作请求的数据包中
	Trimming(context.Context, *TrimmingRequest) (*TransactionActionResponse, error)
	// TrimmingFromInventory 将下面列出的，
	// 位于背包中的物品放置在锻造台中，
	// 并进行对于的锻造台的纹饰操作。
	//
	// - trimItemSlot 处的 1 个装备
	// - materialSlot 处的 1 个材料
	// - templateSlot 处的 1 个模板
	//
	// resultItem 指示期望得到的锻造结果数据。
	// 如果操作成功，则被锻造物品将回到原位。
	//
	// 该操作不支持内联，但它仍然可以被紧缩在单个
	// 的物品堆栈操作请求的数据包中
	TrimmingFromInventory(context.Context, *TrimmingRequest) (*TransactionActionResponse, error)
	// CommitTransaction 将底层操作序列内联到单个物品堆栈操作请求数据包中执行物品堆栈操作事务。
	// 如果没有返回错误，Commit 在完成后将使用 Discord 清空底层操作序列。
	// 应当说明的是，如果事务没有全部成功，则若没有返回错误，则 Discord 仍然会执行。
	//
	// Commit 在设计上考虑并预期事务的所有都会成功，因此内联将尽可能紧凑，而这依赖于“成功”的预期前提。
	// 这意味着，一旦某个步骤失败，那么整个物品堆栈操作都可能失败，并且最终的结果将是未定义的。
	//
	// success 为真指示该事务的全部操作完全成功，若为否则可能部分失败。
	// 作为一种特殊情况，如果底层操作序列为空，则 success 总是真。
	//
	// pk 指示最终编译得到的数据包，它可以用于调试，但不应重新用于发送；
	// serverResponse 则指示租赁服针对 pk 中每个物品堆栈操作的结果
	CommitTransaction(context.Context, *CommitTransactionRequest) (*CommitTransactionResponse, error)
	// CommitItemStackOperations 一次性提交物品堆栈操作列表，避免每个操作都发生一次 RPC。
	//
	// Operations 会被按顺序追加到同一个事务中，并在服务端直接提交。
	CommitItemStackOperations(context.Context, *CommitItemStackOperationsRequest) (*CommitTransactionResponse, error)
	// DiscardTransaction 丢弃曾经执行的更改。
	// 从本质上说，它将清空底层操作序列
	DiscardTransaction(context.Context, *DiscardTransactionRequest) (*DiscardTransactionResponse, error)
	mustEmbedUnimplementedItemStackTransactionServiceServer()
}

